+  }
+
+  async getCurrentAdminMembership(args: { teamId: number; actorUserId: number }) {
+    return this.dbRead.prisma.membership.findFirst({
+      where: {
+        teamId: args.teamId,
+        userId: args.actorUserId,
+        accepted: true,
+        role: {
