+  });
+}
+
+async function addMembership(args: {
+  teamId: number;
+  userId: number;
+  role?: MembershipRole;
+  accepted?: boolean;
+}) {
+  return prisma.membership.create({
+    data: {
+      teamId: args.teamId,
+      userId: args.userId,
+      role: args.role ?? MembershipRole.MEMBER,
+      accepted: args.accepted ?? true,
